 */
protected int findByte(byte value, int pos) {
    if (buffer == null || pos >= buffer.limit()) {
        return -1;
    }
    // Save the original position
    int originalPosition = buffer.position();
    try {
        // Set position to start searching from
        buffer.position(pos);
