/**
 * 使用容差 1e-9 比较两个点是否相等。
 * @param p1 第一个点
 * @param p2 第二个点
 * @return 两个点是否相等
 */
public static boolean equals(Point2D p1, Point2D p2) {
    if (p1 == p2)
        return true;
    if (p1 == null || p2 == null)
        return false;
    double epsilon = 1e-9;
    return Math.abs(p1.getX() - p2.getX()) < epsilon && Math.abs(p1.getY() - p2.getY()) < epsilon;
}

