 */
private Set<V> intersection(Set<V> set1, Set<V> set2) {
    // 创建结果集
    Set<V> result = new HashSet<>();
    // 选择较小的集合进行遍历以提高效率
    if (set1.size() > set2.size()) {
        Set<V> temp = set1;
        set1 = set2;
        set2 = temp;
