/**
 * 将一个 {@link LoggingEvent} 放入缓冲区。如果缓冲区已满，则该事件会被<b>静默丢弃</b>。调用者有责任确保缓冲区有空闲空间。
 */
public void put(LoggingEvent o) {
    if (o != null) {
        // Using offer() instead of put() to avoid blocking
        buffer.offer(o);
    }
