 */
public void add(LoggingEvent event) {
    if (event == null) {
        return;
    }
    // 如果缓冲区已满,移除最早的事件
    if (buffer.size() >= MAX_BUFFER_SIZE) {
        buffer.remove(0);
    }
    // 添加新事件到缓冲区末尾
    buffer.add(event);
}

