 * @param dataset The DataTable to compare with
 * @return true if the buckets are the same, false otherwise
 */
public boolean isCompatible(DataTable dataset) {
    if (dataset == null) {
        return false;
    }
    if (this == dataset) {
        return true;
    }
    if (this.buckets == null && dataset.buckets == null) {
        return true;
    }
    if (this.buckets == null || dataset.buckets == null) {
        return false;
